import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { useFavoritesStore } from '../store/favoritesStore';
import { api } from '../services/api';

export function useFavoritesSync() {
  const queryClient = useQueryClient();
  const { favorites, addFavorite, removeFavorite, setFavorites } = useFavoritesStore();

  // Récupération des favoris serveur
  const { data: serverFavorites = [] } = useQuery({
    queryKey: ['favorites'],
    queryFn: () => api.get('/favorites').then(res => res.data),
    enabled: !!authToken,
  });

  // Mutation ajout
  const addMutation = useMutation({
    mutationFn: (productId: number) => api.post('/favorites', { productId }),
    onSuccess: (_, productId) => {
      queryClient.invalidateQueries(['favorites']);
    },
  });

  // Mutation suppression
  const removeMutation = useMutation({
    mutationFn: (productId: number) => api.delete(`/favorites/${productId}`),
    onSuccess: () => queryClient.invalidateQueries(['favorites']),
  });

  // Synchronisation
  const sync = async () => {
    const localIds = favorites.map(p => p.id);
    const serverIds = serverFavorites;

    // Ajouter au serveur ce qui est local mais pas serveur
    const toAdd = localIds.filter(id => !serverIds.includes(id));
    for (const id of toAdd) await addMutation.mutateAsync(id);

    // Supprimer du serveur ce qui est serveur mais pas local
    const toRemove = serverIds.filter(id => !localIds.includes(id));
    for (const id of toRemove) await removeMutation.mutateAsync(id);

    // Rafraîchir le store local avec l'état serveur
    setFavorites(serverFavorites.map(id => ({ id })));
  };

  return { sync, isSyncing: addMutation.isPending || removeMutation.isPending };
}
